#include<bits/stdc++.h>
using namespace std;
const int N = 5e5+5;
struct node{
    int l,r,id;
}a[N];
int n,m,f[N][30],ans[N];
bool cmp(node d1,node d2){return d1.l<d2.l;}
void Count(int x){
    int lst=a[x].l+m,id=x,sum=1;
    for(int i=20;i>=0;i--)
        if(f[id][i]!=0&&a[f[id][i]].r<lst)
            id=f[id][i],sum+=(1<<i);
    ans[a[x].id]=sum+1;return;
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        a[i].id=i;
        cin>>a[i].l>>a[i].r;
        if(a[i].r<a[i].l)a[i].r+=m;
    }
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++)
        a[i+n].id=i,a[i+n].l=a[i].l+m,a[i+n].r=a[i].r+m;
    for(int i=1,p=1;i<=2*n;i++){
        while(p<=2*n&&a[p].l<=a[i].r)p++;
        f[i][0]=p-1;
    }
    for(int j=1;j<=20;j++)
        for(int i=1;i+(1<<j)-1<=2*n;i++)
            f[i][j]=f[f[i][j-1]][j-1];
    for(int i=1;i<=n;i++)Count(i);
    for(int i=1;i<=n;i++)cout<<ans[i]<<" ";
    return 0;
}
